+import { NextRequest, NextResponse } from "next/server";
+import { fetchJobs } from "@/lib/api/workflowApiClient";
+
+export async function GET(request: NextRequest) {
+  const { searchParams } = request.nextUrl;
+  const assigneeEmail = searchParams.get("assignee_email") ?? undefined;
+  const systemDepartment = searchParams.get("system_department") ?? undefined;
+  const status = searchParams.get("status") ?? undefined;
+  const limit = searchParams.get("limit") ? Number(searchParams.get("limit")) : undefined;
+  const offset = searchParams.get("offset") ? Number(searchParams.get("offset")) : undefined;
+
+  try {
+    const data = await fetchJobs(assigneeEmail, systemDepartment, status, limit, offset);
+    return NextResponse.json(data);
+  } catch (err) {
+    const message = err instanceof Error ? err.message : "Failed to fetch jobs";
+    return NextResponse.json({ error: message }, { status: 500 });
+  }
+}
