@@ -0,0 +1,90 @@
+"use client";
+
+import { useEffect } from "react";
+import { useSession } from "next-auth/react";
+import { Briefcase, Loader2 } from "lucide-react";
+import { Select, SelectContent, SelectItem, SelectTrigger } from "@/components/ui/select";
+import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
+import { useJobStore, selectJobs, selectIsLoading, selectError } from "@/store/jobStore";
+import { truncateText, truncateJobName, MAX_EXTERNAL_ID_LENGTH } from "@/lib/utils/jobFormatting";
+
+export default function JobSelector() {
+  const { data: session } = useSession();
+  const selectedJob = useJobStore((state) => state.selectedJob);
+  const setSelectedJob = useJobStore((state) => state.setSelectedJob);
+  const jobs = useJobStore(selectJobs);
+  const isLoading = useJobStore(selectIsLoading);
+  const error = useJobStore(selectError);
+
+  // Fetch jobs if the store is empty (e.g. user had a stored job and modal was skipped)
+  useEffect(() => {
+    if (jobs.length === 0 && !isLoading) {
+      const userEmail = session?.user?.email ?? undefined;
+      useJobStore.getState().loadJobs(userEmail);
+    }
+  // eslint-disable-next-line react-hooks/exhaustive-deps
+  }, [session?.user?.email]);
+
+  const selectedJobData = jobs.find((job) => job.id === selectedJob);
+
+  // Hide entirely if loading finished with no jobs or an error
+  if (!isLoading && (error || jobs.length === 0)) {
+    return null;
+  }
+
+  const handleJobSelect = (jobId: string) => {
+    setSelectedJob(jobId);
+  };
+
+  return (
+    <div className="flex items-center gap-2">
+      <Briefcase className="size-4 text-muted-foreground" />
+      <Select onValueChange={handleJobSelect} value={selectedJob || undefined}>
+        <SelectTrigger className="w-[260px] h-9 bg-background">
+          {isLoading ? (
+            <div className="flex items-center gap-2">
+              <Loader2 className="size-3 animate-spin" />
+              <span className="text-muted-foreground text-sm">Loading...</span>
+            </div>
+          ) : error ? (
+            <span className="text-destructive text-sm">Error loading jobs</span>
+          ) : selectedJobData ? (
+            <div className="flex items-center gap-2">
+              <span className="text-xs text-muted-foreground bg-muted px-1.5 py-0.5 rounded font-medium w-[70px] text-center truncate" title={selectedJobData.external_id.toUpperCase()}>
+                {truncateText(selectedJobData.external_id.toUpperCase(), MAX_EXTERNAL_ID_LENGTH)}
+              </span>
+              <Tooltip>
+                <TooltipTrigger asChild>
+                  <span className="truncate max-w-[150px]">
+                    {truncateJobName(selectedJobData.name)}
+                  </span>
+                </TooltipTrigger>
+                <TooltipContent side="bottom">{selectedJobData.name}</TooltipContent>
+              </Tooltip>
+            </div>
+          ) : (
+            <span className="text-muted-foreground">Select a job</span>
+          )}
+        </SelectTrigger>
+        <SelectContent>
+          {jobs.length === 0 ? (
+            <div className="px-2 py-3 text-sm text-muted-foreground text-center">
+              No jobs available
+            </div>
+          ) : (
+            jobs.map((job) => (
+              <SelectItem key={job.id} value={job.id}>
+                <div className="flex items-center gap-2">
+                  <span className="text-xs text-muted-foreground bg-muted px-1.5 py-0.5 rounded font-medium w-[70px] text-center truncate" title={job.external_id.toUpperCase()}>
+                    {truncateText(job.external_id.toUpperCase(), MAX_EXTERNAL_ID_LENGTH)}
+                  </span>
+                  <span>{truncateJobName(job.name)}</span>
+                </div>
+              </SelectItem>
+            ))
+          )}
+        </SelectContent>
+      </Select>
+    </div>
+  );
+}
