+import { create } from "zustand";
+import { immer } from "zustand/middleware/immer";
+import { JobResponse } from "@/lib/api/workflowApiClient";
+
+export interface Job {
+  id: string;
+  external_id: string;
+  name: string;
+  description?: string;
+}
+
+// Mapper function to convert API response to UI Job format
+const mapApiJobToJob = (apiJob: JobResponse): Job => {
+  return {
+    id: apiJob.id,
+    external_id: apiJob.external_job_id || apiJob.id,
+    name: apiJob.name || apiJob.external_job_id || apiJob.id,
+    description: apiJob.status,
+  };
+};
+
+interface JobState {
+  jobs: Job[];
+  isLoading: boolean;
+  error: string | null;
+  selectedJob: string | null;
+  showJobModal: boolean;
+
+  // Actions
+  setSelectedJob: (jobId: string | null) => void;
+  openJobModal: () => void;
+  closeJobModal: () => void;
+  loadJobs: (assigneeEmail?: string, systemDepartment?: string, status?: string) => Promise<void>;
+}
+
+export const useJobStore = create<JobState>()(
+  immer((set) => ({
+    jobs: [],
+    isLoading: false,
+    error: null,
+    selectedJob: null,
+    showJobModal: false,
+
+    setSelectedJob: (jobId: string | null) => {
+      set((state) => {
+        state.selectedJob = jobId;
+      });
+      // Persist to sessionStorage for session-based persistence
+      if (typeof window !== "undefined") {
+        if (jobId) {
+          sessionStorage.setItem("selectedJob", jobId);
+        } else {
+          sessionStorage.removeItem("selectedJob");
+        }
+      }
+    },
+
+    openJobModal: () => {
+      set((state) => {
+        state.showJobModal = true;
+      });
+    },
+
+    closeJobModal: () => {
+      set((state) => {
+        state.showJobModal = false;
+      });
+    },
+
+    loadJobs: async (assigneeEmail?: string, systemDepartment?: string, status?: string) => {
+      set((state) => {
+        state.isLoading = true;
+        state.error = null;
+      });
+
+      try {
+        const params = new URLSearchParams();
+        if (assigneeEmail) params.append("assignee_email", assigneeEmail);
+        if (systemDepartment) params.append("system_department", systemDepartment);
+        if (status) params.append("status", status);
+        const res = await fetch(`/api/jobs?${params.toString()}`);
+        if (!res.ok) {
+          const body = await res.json();
+          throw new Error(body.error || "Failed to fetch jobs");
+        }
+        const response = await res.json();
+        const mappedJobs = response.jobs.map(mapApiJobToJob);
+
+        set((state) => {
+          state.jobs = mappedJobs;
+          state.isLoading = false;
+        });
+      } catch (err) {
+        set((state) => {
+          state.error = err instanceof Error ? err.message : "Failed to fetch jobs";
+          state.isLoading = false;
+          state.jobs = [];
+        });
+      }
+    },
+  })),
+);
+
+// Initialize from sessionStorage on client side
+export const initializeJobFromSession = () => {
+  if (typeof window !== "undefined") {
+    const storedJob = sessionStorage.getItem("selectedJob");
+    if (storedJob) {
+      useJobStore.getState().setSelectedJob(storedJob);
+    }
+  }
+};
+
+// Selectors
+export const selectSelectedJob = (state: JobState) => state.selectedJob;
+export const selectShowJobModal = (state: JobState) => state.showJobModal;
+export const selectSelectedJobData = (state: JobState) =>
+  state.jobs.find((j) => j.id === state.selectedJob);
+export const selectIsLoading = (state: JobState) => state.isLoading;
+export const selectError = (state: JobState) => state.error;
+export const selectJobs = (state: JobState) => state.jobs;

