// Helper to append workflow_job_id if a job is selected
const withJobId = (url: string): string => {
  if (typeof window === "undefined") return url;
  const jobId = sessionStorage.getItem("selectedJob");
  if (!jobId) return url;
  const separator = url.includes("?") ? "&" : "?";
  return `${url}${separator}workflow_job_id=${encodeURIComponent(jobId)}`;
};

